async (params, browser) => {
  // Open design type page
  await browser.open(`https://www.canva.com/${params.design_type}/`)

  // Wait for page to load
  await browser.waitForSelector('h1, [role=\'heading\'], main', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load content
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Extract design type details
  const design_data = await browser.evaluate(`const titleEl = document.querySelector('h1, [role="heading"]'); const metaDesc = document.querySelector('meta[name="description"]'); const descEl = document.querySelector('main p, article p, section p'); const templates = []; const seen = new Set(); const templateEls = document.querySelectorAll('a[href*="/templates/"]'); for (let i = 0; i < templateEls.length && templates.length < 12; i++) { const el = templateEls[i]; const href = el.href || ''; if (!href || seen.has(href)) continue; seen.add(href); const nameEl = el.querySelector('h3, h4, [aria-label]'); const imgEl = el.querySelector('img'); const ariaLabel = el.getAttribute('aria-label') || ''; const proEl = el.querySelector('[aria-label*="Pro"], [aria-label*="premium"]'); templates.push({ title: ariaLabel || (nameEl ? (nameEl.getAttribute('aria-label') || nameEl.textContent.trim()) : ''), is_premium: !!proEl, image: imgEl ? imgEl.getAttribute('src') : '', url: href }); } const featureEls = document.querySelectorAll('section h2, section h3'); const features = []; featureEls.forEach(function(el) { const t = el.textContent.trim(); if (t && t.length < 100 && !features.includes(t)) features.push(t); }); const subcategoryEls = document.querySelectorAll('nav a[href*="/templates/"], a[href*="/templates/s/"]'); const subcategories = []; subcategoryEls.forEach(function(el) { const t = el.textContent.trim(); if (t && t.length < 80 && !subcategories.includes(t)) subcategories.push(t); }); return { design_type: params.design_type, title: titleEl ? titleEl.textContent.trim() : '', description: metaDesc ? metaDesc.getAttribute('content') : (descEl ? descEl.textContent.trim().substring(0, 500) : ''), features: features.slice(0, 10), subcategories: subcategories.slice(0, 10), template_count: templates.length, templates: templates, url: window.location.href }`)

  return design_data
}
